const records = $input.item.json.records || [];
return records.map(r => ({
  json: {
    record_id: r.id,
    agent_name: r.fields.agent_name || '',
    agency_name: r.fields.agency_name || '',
    website: r.fields.website || '',
    domain: r.fields.domain || '',
    google_rating: r.fields.google_rating || null,
    review_count: r.fields.review_count || 0,
    has_live_chat: r.fields.has_live_chat || false,
    contact_form_found: r.fields.contact_form_found || false,
    response_time_minutes: r.fields.response_time_minutes || null,
    city: r.fields.city || '',
    state: r.fields.state || ''
  }
}));

const html = $input.item.json.data || $input.item.json || '';
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);

let text = htmlStr
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
  .replace(/\s+/g, ' ').trim().substring(0, 3000);

const record = $('Split Into Items').item.json;
return [{ json: { ...record, website_text: text, website_fetch_status: 'Success' } }];

const response = $input.item.json;
const content = response.content?.[0]?.text || '';
const record = $('Build Claude Prompt').item.json;

let parsed;
try {
  const clean = content.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { score: 0, signals: ['Parse error — Claude returned invalid JSON'], summary: 'Failed to parse Claude response', uses_crm: null, crm_mentioned: null, has_scheduler: null, is_solo_agent: null };
}

return [{ json: {
  ...record,
  ai_score: parsed.score || 0,
  ai_signals: Array.isArray(parsed.signals) ? parsed.signals.join(', ') : '',
  ai_summary: parsed.summary || '',
  uses_crm: parsed.uses_crm || false,
  crm_mentioned: parsed.crm_mentioned || null,
  has_scheduler: parsed.has_scheduler || false,
  is_solo_agent: parsed.is_solo_agent || false
} }];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: { skipped: true } }];
return [{ json: { slackUrl, slackBody: { text: '📊 *RE Workflow D — Agent Scored*\nAI scoring run complete. Check Agents table for updated ai_score values.' } } }];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: {} }];
const err = $input.item.json;
return [{ json: { slackUrl, slackBody: { text: `🚨 *RE Workflow D Error*\n${err.execution?.error?.message || 'Unknown error'}` } } }];
